public class BubbleSort {
    public static void sort(int[] arr) {
        // Input: Array 'arr' received for in-place modification
        int n = arr.length;

        // Process: Nested swapping passes
        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < n - i - 1; j++) {
                if (arr[j] > arr[j + 1]) {
                    // Storage & Process: Swap logic
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;
                }
            }
        }
        // Output: Array is sorted in-place
    }
}

