public class SelectionSort {
    public static void sort(int[] arr) {
        // Input: Array parameter to sort
        int n = arr.length;

        // Process: Select minimum and swap
        for (int i = 0; i < n - 1; i++) {
            // Storage: Track index of minimum
            int minIndex = i;

            for (int j = i + 1; j < n; j++) {
                if (arr[j] < arr[minIndex]) {
                    minIndex = j; // Update storage pointer
                }
            }

            // Process: Swap minimum to its correct place
            int temp = arr[minIndex];
            arr[minIndex] = arr[i];
            arr[i] = temp;
        }
    }
}

