public class InsertionSort {
    public static void sort(int[] arr) {
        // Input: Array reference
        int n = arr.length; // Storage

        // Process: Dynamic shifting inserts
        for (int i = 1; i < n; ++i) {
            int key = arr[i]; // Storage: Target element
            int j = i - 1;    // Storage: Prior element index

            while (j >= 0 && arr[j] > key) {
                arr[j + 1] = arr[j]; // Process: Shift values right
                j = j - 1;
            }
            arr[j + 1] = key; // Process: Insert key
        }
    }
}
